      ) {
        let numParams = 8
        guard parameters.count == numParams
        else { exchangeStructure.error = "number of p21 parameters(\(parameters.count)) are different from expected(\(numParams)) for partial entity(\(Self.entityName)) constructor"; return nil }

        guard case .success(let p0) = exchangeStructure.recoverRequiredParameter(as: SDAI.LIST<
          eLOCAL_B_SPLINE.PRef>.self, from: parameters[0])
        else { exchangeStructure.add(errorContext: "while recovering parameter [0]B_SPLINES for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p1) = exchangeStructure.recoverRequiredParameter(as: tSPLINE_KNOT_VALUES.self, from: parameters[1])
