        self.init( B_SPLINES: p0, KNOT_VALUES: p1, CONTROL_POINTS_LIST: p2, SCALING_FACTORS: p3, CLOSED_CURVE: SDAI.LOGICAL(p4), LOCALLY_REFINED_SPLINE_TYPE: p5, SELF_INTERSECT: SDAI.LOGICAL(p6), DOMAIN: p7 )
